import React, { useState, useRef, useEffect } from "react";
import { aiAPI } from "../utils/api";
import { SparklesIcon, PaperAirplaneIcon, BriefcaseIcon, ChartBarIcon } from "@heroicons/react/24/outline";
import { SparklesIcon as SparklesSolid } from "@heroicons/react/24/solid";
import toast from "react-hot-toast";
import clsx from "clsx";
const QUICK = ["What is the leave policy?","How to apply for sick leave?","Explain performance review process","How is salary calculated?","What are company benefits?"];
const TOOLS = [{id:"chat",label:"HR Chatbot",icon:SparklesIcon},{id:"jd",label:"JD Generator",icon:BriefcaseIcon},{id:"attrition",label:"Attrition Risk",icon:ChartBarIcon}];
function Message({ msg }) {
  const isUser = msg.role==="user";
  return (
    <div className={clsx("flex gap-3",isUser?"flex-row-reverse":"flex-row")}>
      <div className={clsx("w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 text-white text-xs font-bold",isUser?"bg-primary-500":"bg-gradient-to-br from-primary-500 to-purple-600")}>{isUser?"You":<SparklesSolid className="w-4 h-4"/>}</div>
      <div className={clsx("max-w-[78%] rounded-2xl px-4 py-3 text-sm leading-relaxed",isUser?"bg-primary-600 text-white rounded-tr-sm":"bg-white border border-slate-100 text-slate-800 rounded-tl-sm shadow-sm")}>
        {msg.content}{msg.loading&&<span className="inline-flex gap-1 ml-2">{[0,1,2].map(i=>(<span key={i} className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" style={{animationDelay:`${i*0.15}s`}}/>))}</span>}
      </div>
    </div>
  );
}
export default function AIAssistant() {
  const [activeTool, setActiveTool] = useState("chat");
  const [messages, setMessages] = useState([{role:"assistant",content:"Hi! I am HRBot. Ask me anything about HR policies, leave, payroll, or company guidelines."}]);
  const [input, setInput] = useState("");
  const [sending, setSending] = useState(false);
  const [jdForm, setJdForm] = useState({title:"",department:"",experienceMin:2,experienceMax:5,skills:""});
  const [jdResult, setJdResult] = useState(null);
  const bottomRef = useRef(null);
  useEffect(()=>{ bottomRef.current?.scrollIntoView({behavior:"smooth"}); },[messages]);
  const sendMessage = async (text=input) => {
    if (!text.trim()) return;
    setMessages(m=>[...m,{role:"user",content:text},{role:"assistant",content:"",loading:true}]);
    setInput(""); setSending(true);
    try {
      const {data} = await aiAPI.chatbot(text);
      setMessages(m=>{ const u=[...m]; u[u.length-1]={role:"assistant",content:data.data.reply}; return u; });
    } catch { setMessages(m=>{ const u=[...m]; u[u.length-1]={role:"assistant",content:"Sorry, I encountered an error. Please try again."}; return u; }); }
    setSending(false);
  };
  const generateJD = async () => {
    try {
      const {data} = await aiAPI.generateJD({...jdForm,skills:jdForm.skills.split(",").map(s=>s.trim())});
      setJdResult(data.data); toast.success("JD generated!");
    } catch { toast.error("Generation failed"); }
  };
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-center gap-2"><div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-purple-600 rounded-lg flex items-center justify-center"><SparklesSolid className="w-4 h-4 text-white"/></div><div><h1 className="page-title">AI Assistant</h1></div></div>
      <div className="flex gap-2">{TOOLS.map(t=>(<button key={t.id} onClick={()=>setActiveTool(t.id)} className={clsx("flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium transition-all border",activeTool===t.id?"bg-primary-600 text-white border-primary-600":"bg-white text-slate-600 border-slate-200 hover:bg-slate-50")}><t.icon className="w-4 h-4"/>{t.label}</button>))}</div>
      <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">
        <div className="lg:col-span-3 card flex flex-col" style={{height:"600px"}}>
          {activeTool==="chat"?(<>
            <div className="flex-1 overflow-y-auto space-y-4 pr-1 pb-2">{messages.map((msg,i)=>(<Message key={i} msg={msg}/>))}<div ref={bottomRef}/></div>
            <div className="pt-3 border-t border-slate-100">
              <div className="flex flex-wrap gap-1.5 mb-3">{QUICK.map(p=>(<button key={p} onClick={()=>sendMessage(p)} className="text-xs px-3 py-1 bg-primary-50 text-primary-600 rounded-full hover:bg-primary-100">{p}</button>))}</div>
              <div className="flex gap-2"><input className="input flex-1" placeholder="Ask about HR policies…" value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&!e.shiftKey&&sendMessage()} disabled={sending}/><button onClick={()=>sendMessage()} disabled={sending||!input.trim()} className="btn-primary px-3"><PaperAirplaneIcon className="w-4 h-4"/></button></div>
            </div>
          </>):activeTool==="jd"?(<div className="overflow-y-auto space-y-3">
            <h3 className="font-semibold text-slate-800">AI Job Description Generator</h3>
            {[["title","Job Title"],["department","Department"]].map(([k,l])=>(<div key={k}><label className="label text-xs">{l}</label><input className="input text-sm" value={jdForm[k]} onChange={e=>setJdForm(f=>({...f,[k]:e.target.value}))}/></div>))}
            <div><label className="label text-xs">Skills (comma-separated)</label><input className="input text-sm" placeholder="React, Node.js" value={jdForm.skills} onChange={e=>setJdForm(f=>({...f,skills:e.target.value}))}/></div>
            <button onClick={generateJD} disabled={!jdForm.title} className="btn-primary w-full"><SparklesSolid className="w-4 h-4"/>Generate JD</button>
            {jdResult&&<div className="bg-slate-50 rounded-xl p-4 space-y-2 text-sm overflow-y-auto max-h-64"><p className="font-semibold text-slate-700">Overview</p><p className="text-slate-600 leading-relaxed">{jdResult.description}</p>{jdResult.responsibilities?.length>0&&<><p className="font-semibold text-slate-700 mt-2">Responsibilities</p><ul className="space-y-1">{jdResult.responsibilities.map((r,i)=>(<li key={i} className="flex gap-2 text-slate-600"><span className="text-primary-500">·</span>{r}</li>))}</ul></>}</div>}
          </div>):(<div className="overflow-y-auto space-y-3">
            <h3 className="font-semibold text-slate-800">Attrition Risk Analysis</h3>
            <p className="text-sm text-slate-600">Visit individual employee profiles and click Run Analysis to generate AI-powered attrition risk scores.</p>
            <div className="bg-primary-50 rounded-xl p-4 text-sm text-primary-700">Go to Employees → Select an employee → AI Insights tab → Run Analysis</div>
          </div>)}
        </div>
        <div className="lg:col-span-2 space-y-4">
          <div className="card ai-glow">
            <div className="flex items-center gap-2 mb-3"><SparklesSolid className="w-4 h-4 text-primary-500"/><h3 className="font-semibold text-slate-800 text-sm">AI Capabilities</h3></div>
            <ul className="space-y-2 text-sm text-slate-600">{["HR Q&A Chatbot","Job Description Generation","Resume Screening & Scoring","Attrition Prediction","Performance Review Writing","Leave Risk Analysis","Workforce Insights"].map(item=>(<li key={item} className="flex items-center gap-2 before:content-['·'] before:text-primary-500 before:font-bold">{item}</li>))}</ul>
          </div>
          <div className="card bg-primary-50 border-primary-100">
            <p className="text-xs font-semibold text-primary-700 mb-1">AI Model</p>
            <p className="text-sm text-slate-700">GPT-4o powers screening and analysis. GPT-4o-mini handles the chatbot for fast responses.</p>
          </div>
        </div>
      </div>
    </div>
  );
}
